sql:
SELECT size_name, description
FROM button_sizes
WHERE size_id = 1;

SELECT size_name, description
FROM button_sizes
WHERE width > 100;

SELECT style_name
FROM button_styles
WHERE style_id = 1;

SELECT type_name
FROM button_types
WHERE default_style_id = 1;

SELECT COUNT(*) AS total_feedback
FROM component_feedback
WHERE component_id = 0;

SELECT state_name
FROM button_states
WHERE state_name = 'Enabled';

SELECT component_name 
FROM ui_components 
ORDER BY component_name;

SELECT size_name
  FROM button_sizes
  ORDER BY width DESC;

SELECT MAX(update_date)
  FROM component_updates
  WHERE component_id = 1;

SELECT component_id
FROM component_usage
WHERE usage_count = (SELECT MAX(usage_count) FROM component_usage);

SELECT size_name
FROM button_sizes
ORDER BY size_name ASC;

SELECT AVG(rating) AS average_rating
FROM component_feedback
WHERE component_id = 1;

SELECT component_name
FROM ui_components
WHERE created_date = (SELECT MAX(created_date) FROM ui_components);

SELECT type_name, color_scheme
FROM button_types
ORDER BY type_name;

external_knowledge:
- 'crown jewels' refers to the most valuable or sought-after components in a project, in this case, the most frequently used components; 
- 'polished the most' refers to the components that are updated the most by a specific user; 
- 'favorite craftsmen' refers to the users who have made the most updates to a component; 
- 'sparkle' refers to the total usage count of a component, with higher counts indicating more sparkle.

